const fecha = new Date().toLocaleDateString('es-CL',  { timeZone: 'America/Santiago' });
const WF   = '[WF-1.9]';
const AUTH = 'Basic amFpbWVxdi4yNjA5QGdtYWlsLmNvbTpBVEFUVDN4RmZHRjBOcC1xZWhIekZTaU1vbHItWEV2TndhemRCMVplcnNQVi1FZ2dBSjVYQ2sxZHBzbHI0MEJCZkR4dzdlOGJJVkoxZkFwZGlmaVU1VG1laEIyQXQ1c0lfZGxaZnRyN1NhczlIc2UwYmRUc0RyaElFOW9oOGJYMERqcVdlQ2xyelJ4OGJFM0VocUFEVzZLUGNSMGpTVDV2WE9fRFgwcjMyVkZjd3lKZFhNUjV3Njg9RDI0NkEzOUI=';

const jiraRequest = (path, method, body) => new Promise((resolve, reject) => {
  const payload = body ? JSON.stringify(body) : null;
  const req = https.request({
    hostname: 'qaprocess1.atlassian.net',
    path, method,
    headers: { 'Authorization': AUTH, 'Content-Type': 'application/json', ...(payload ? { 'Content-Length': Buffer.byteLength(payload) } : {}) }
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try { resolve({ status: res.statusCode, body: data ? JSON.parse(data) : {} }); }
      catch(e) { resolve({ status: res.statusCode, body: data }); }
    });
  });
  req.on('error', reject);
  if (payload) req.write(payload);
  req.end();
});

const created = await jiraRequest('/rest/api/3/issue', 'POST', {
  fields: {
    project: { key: 'KAN' },
